// Mock AI Service - Simulates Python FastAPI backend responses
// In production, these would call the Node.js API which forwards to Python

export interface PlayerData {
  id: string;
  globalId?: number;
  shirtNumber?: number;
  name: string;
  age: number;
  position: string;
  team: string;
  nationality: string;
  comp?: string;
  imageUrl?: string;
  stats: {
    matches: number;
    goals: number;
    assists: number;
    tackles?: number;
    interceptions?: number;
    minutesPlayed: number;
    injuries: number;
    saves?: number;
    cleanSheets?: number;
    savePerMatch?: number;
    goalsConceded?: number;
    penaltiesSaved?: number;
  };
  physical: {
    height: number;
    weight: number;
    sprintSpeed: number;
    stamina: number;
    strength: number;
  };
  csvData?: {
    '90s': number;
    comp: string;
  };
}

export interface InjuryPredictionRequest {
  playerId: string;
  historicalData: {
    previousInjuries: number;
    matchesPerSeason: number;
    avgMinutesPerMatch: number;
    age: number;
    position: string;
    trainingLoad: number;
    restDays: number;
  };
}

export interface InjuryPredictionResponse {
  playerId: string;
  riskProbability: number;
  riskLevel: 'low' | 'medium' | 'high';
  topRiskFactors: Array<{
    factor: string;
    impact: number;
    description: string;
  }>;
  recommendations: string[];
  modelConfidence: number;
  timestamp: string;
}

export interface MarketValueRequest {
  playerId: string;
  performanceData: {
    goals: number;
    assists: number;
    matches: number;
    minutesPlayed: number;
    passAccuracy: number;
    tacklesWon: number;
    aerialDuelsWon: number;
  };
  physicalData: {
    age: number;
    height: number;
    sprintSpeed: number;
    stamina: number;
  };
  contractData: {
    yearsRemaining: number;
    currentClubTier: number;
  };
}

export interface MarketValueResponse {
  playerId: string;
  predictedValue: number;
  valueRange: {
    min: number;
    max: number;
  };
  valueFactors: Array<{
    factor: string;
    contribution: number;
    trend: 'up' | 'down' | 'stable';
  }>;
  comparablePlayers: Array<{
    name: string;
    value: number;
    similarity: number;
  }>;
  modelConfidence: number;
  inputStats?: Record<string, unknown>;
  timestamp: string;
}

export interface VideoAnalysisRequest {
  videoPath: string;
  analysisType: 'full' | 'heatmap' | 'tracking' | 'poses';
}

export interface VideoAnalysisResponse {
  videoId: string;
  status: 'processing' | 'completed' | 'failed';
  progress: number;
  results?: {
    annotatedVideoPath: string;
    heatmapPath: string;
    playerMetrics: Array<{
      playerId: string;
      distanceCovered: number;
      topSpeed: number;
      avgSpeed: number;
      sprintCount: number;
      heatmapZones: number[];
    }>;
    teamFormation: string;
    passNetwork: Array<{
      from: string;
      to: string;
      count: number;
    }>;
  };
  timestamp: string;
}

// Simulate network delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

