// Injury Prediction Service (Simulates Random Forest + XGBoost + Logistic Regression)
export async function predictInjury(request: InjuryPredictionRequest): Promise<InjuryPredictionResponse> {
  await delay(800 + Math.random() * 400);

  const { historicalData } = request;
  
  // Mock risk calculation based on factors
  let baseRisk = 0.15;
  
  // Age factor
  if (historicalData.age > 30) baseRisk += 0.15;
  else if (historicalData.age > 27) baseRisk += 0.08;
  
  // Previous injuries
  baseRisk += historicalData.previousInjuries * 0.12;
  
  // Training load
  if (historicalData.trainingLoad > 80) baseRisk += 0.1;
  
  // Rest days
  if (historicalData.restDays < 2) baseRisk += 0.12;
  
  // Minutes per match
  if (historicalData.avgMinutesPerMatch > 85) baseRisk += 0.05;
  
  // Position risk
  if (['Forward', 'Midfielder'].includes(historicalData.position)) {
    baseRisk += 0.05;
  }
  
  const riskProbability = Math.min(0.95, Math.max(0.05, baseRisk + (Math.random() * 0.1 - 0.05)));
  
  const riskLevel: 'low' | 'medium' | 'high' = 
    riskProbability < 0.3 ? 'low' : 
    riskProbability < 0.6 ? 'medium' : 'high';

  const factors = [
    { factor: 'Previous Injuries', impact: historicalData.previousInjuries * 0.12, description: 'History of injuries increases recurrence risk' },
    { factor: 'Training Load', impact: historicalData.trainingLoad > 80 ? 0.15 : 0.05, description: 'High training intensity without adequate recovery' },
    { factor: 'Age Factor', impact: historicalData.age > 30 ? 0.15 : historicalData.age > 27 ? 0.08 : 0.02, description: 'Age-related muscle fatigue accumulation' },
    { factor: 'Match Frequency', impact: historicalData.matchesPerSeason > 50 ? 0.1 : 0.03, description: 'High match density affecting recovery' },
    { factor: 'Rest Days', impact: historicalData.restDays < 2 ? 0.12 : 0.02, description: 'Insufficient recovery time between sessions' },
  ].sort((a, b) => b.impact - a.impact);

  const recommendations = [];
  if (riskLevel === 'high') {
    recommendations.push('Reduce training intensity by 20% for the next 2 weeks');
    recommendations.push('Increase rest days between matches to minimum 3 days');
    recommendations.push('Implement personalized recovery protocol');
  } else if (riskLevel === 'medium') {
    recommendations.push('Monitor training load closely');
    recommendations.push('Consider rotation for high-intensity matches');
  } else {
    recommendations.push('Maintain current training regimen');
    recommendations.push('Continue regular physiotherapy sessions');
  }

  return {
    playerId: request.playerId,
    riskProbability,
    riskLevel,
    topRiskFactors: factors.slice(0, 5),
    recommendations,
    modelConfidence: 0.87 + Math.random() * 0.08,
    timestamp: new Date().toISOString()
  };
}

// Market Value Prediction Service
export async function predictMarketValue(request: MarketValueRequest): Promise<MarketValueResponse> {
  await delay(600 + Math.random() * 400);

  const { performanceData, physicalData, contractData } = request;
  
  // Base value calculation (in millions EUR)
  let baseValue = 10;
  
  // Goals contribution
  baseValue += performanceData.goals * 2.5;
  
  // Assists contribution
  baseValue += performanceData.assists * 1.8;
  
  // Age factor (peak value at 25-27)
  const agePeak = 26;
  const ageDiff = Math.abs(physicalData.age - agePeak);
  const ageFactor = Math.max(0.5, 1 - (ageDiff * 0.06));
  baseValue *= ageFactor;
  
  // Minutes played factor
  baseValue *= (performanceData.minutesPlayed / 3000);
  
  // Physical attributes bonus
  if (physicalData.sprintSpeed > 90) baseValue *= 1.15;
  if (physicalData.stamina > 90) baseValue *= 1.1;
  
  // Contract factor
  baseValue *= (1 + contractData.yearsRemaining * 0.1);
  
  // Club tier factor
  baseValue *= (1 + (5 - contractData.currentClubTier) * 0.1);
  
  const predictedValue = Math.round(baseValue * (0.9 + Math.random() * 0.2) * 100) / 100;
  
  const valueFactors: Array<{ factor: string; contribution: number; trend: 'up' | 'down' | 'stable' }> = [
    { factor: 'Goal Scoring', contribution: performanceData.goals * 2.5 / predictedValue * 100, trend: performanceData.goals > 15 ? 'up' : 'stable' },
    { factor: 'Age Profile', contribution: (1 - ageFactor) * 100, trend: physicalData.age < 26 ? 'up' : 'down' },
    { factor: 'Physical Attributes', contribution: 15, trend: 'stable' },
    { factor: 'Contract Situation', contribution: contractData.yearsRemaining * 5, trend: 'stable' },
    { factor: 'Playing Time', contribution: (performanceData.minutesPlayed / 3000) * 20, trend: 'up' },
  ];

  const comparablePlayers = [
    { name: 'Similar Player A', value: predictedValue * (0.85 + Math.random() * 0.3), similarity: 0.85 + Math.random() * 0.1 },
    { name: 'Similar Player B', value: predictedValue * (0.9 + Math.random() * 0.25), similarity: 0.8 + Math.random() * 0.1 },
    { name: 'Similar Player C', value: predictedValue * (0.8 + Math.random() * 0.4), similarity: 0.75 + Math.random() * 0.1 },
  ];

  return {
    playerId: request.playerId,
    predictedValue,
    valueRange: {
      min: Math.round(predictedValue * 0.8 * 100) / 100,
      max: Math.round(predictedValue * 1.2 * 100) / 100
    },
    valueFactors,
    comparablePlayers,
    modelConfidence: 0.82 + Math.random() * 0.1,
    timestamp: new Date().toISOString()
  };
}

// Video Analysis Service (Simulates YOLOv8 + OpenPose)
export async function analyzeVideo(request: VideoAnalysisRequest): Promise<VideoAnalysisResponse> {
  // Return immediately with processing status, then simulate completion
  const videoId = `vid_${Date.now()}`;
  
  return {
    videoId,
    status: 'completed',
    progress: 100,
    results: {
      annotatedVideoPath: `/outputs/${videoId}_annotated.mp4`,
      heatmapPath: `/outputs/${videoId}_heatmap.png`,
      playerMetrics: [
        { playerId: 'p1', distanceCovered: 10.5, topSpeed: 34.2, avgSpeed: 8.1, sprintCount: 24, heatmapZones: [15, 25, 35, 20, 5] },
        { playerId: 'p2', distanceCovered: 11.8, topSpeed: 31.5, avgSpeed: 9.2, sprintCount: 18, heatmapZones: [10, 40, 30, 15, 5] },
        { playerId: 'p3', distanceCovered: 9.2, topSpeed: 28.8, avgSpeed: 7.5, sprintCount: 12, heatmapZones: [5, 15, 20, 40, 20] },
      ],
      teamFormation: '4-3-3',
      passNetwork: [
        { from: 'p1', to: 'p2', count: 15 },
        { from: 'p2', to: 'p3', count: 22 },
        { from: 'p3', to: 'p1', count: 8 },
        { from: 'p2', to: 'p1', count: 18 },
      ]
    },
    timestamp: new Date().toISOString()
  };
}

// Get player by ID (deprecated - use playerService instead)
export function getPlayerById(id: string): PlayerData | undefined {
  return mockPlayers.find(p => p.id === id);
}

// Get all players (deprecated - use playerService instead)
// This is kept for backward compatibility but will be merged with user-specific players
export function getAllPlayers(): PlayerData[] {
  return mockPlayers;
}
